import React from "react";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const nav = useNavigate();

  return (
    <div style={styles.container}>

      <div style={styles.card}>

        <h1 style={styles.title}>
          Daily Worker Platform
        </h1>

        <p style={styles.subtitle}>
          Connect customers and workers instantly.  
          Post jobs, accept work, and manage everything in one place.
        </p>

        <div style={styles.btnRow}>

          <button
            style={styles.primary}
            onClick={() => nav("/login")}
          >
            Get Started
          </button>

          <button
            style={styles.secondary}
            onClick={() => nav("/register")}
          >
            Create Account
          </button>

        </div>

      </div>

    </div>
  );
};

export default Home;

const styles = {
  container: {
    height: "100vh",
    background: "#0b1220",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Segoe UI"
  },

  card: {
    width: "500px",
    padding: "40px",
    borderRadius: "16px",
    background: "#111a2e",
    border: "1px solid #1f2a44",
    textAlign: "center"
  },

  title: {
    fontSize: "34px",
    color: "white",
    marginBottom: "10px"
  },

  subtitle: {
    color: "#94a3b8",
    fontSize: "15px",
    lineHeight: "22px",
    marginBottom: "25px"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    justifyContent: "center"
  },

  primary: {
    padding: "10px 18px",
    background: "#22c55e",
    border: "none",
    color: "white",
    borderRadius: "8px",
    cursor: "pointer"
  },

  secondary: {
    padding: "10px 18px",
    background: "transparent",
    border: "1px solid #22c55e",
    color: "#22c55e",
    borderRadius: "8px",
    cursor: "pointer"
  }
};
